<form class="admin-debt-form" method="post" action="<?=BASE_URL?>/index.php?ruta=<?=$modo==='crear'?'admin-adeudo-guardar':'admin-adeudo-actualizar'?>"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars($csrfToken,ENT_QUOTES,'UTF-8')?>"><?php if($modo==='editar'):?><input type="hidden" name="id_adeudo" value="<?=(int)$adeudo['id_adeudo']?>"><div class="admin-debt-field admin-debt-readonly"><strong>Alumno</strong><span><?=htmlspecialchars($adeudo['matricula'].' - '.$adeudo['nombre'],ENT_QUOTES,'UTF-8')?></span></div><?php else:?><label class="admin-debt-field">Alumno<select name="id_alumno" required><option value="">Selecciona un alumno</option><?php foreach($alumnos as $a):?><option value="<?=(int)$a['id_alumno']?>"><?=htmlspecialchars($a['matricula'].' - '.$a['nombre'],ENT_QUOTES,'UTF-8')?></option><?php endforeach;?></select></label><?php endif;?><label class="admin-debt-field">Periodo<input type="month" name="periodo" value="<?=htmlspecialchars($adeudo['periodo'],ENT_QUOTES,'UTF-8')?>" required></label><?php foreach(['mensualidad'=>'Mensualidad','aportacion_tsu'=>'Aportación TSU','atraso'=>'Atraso','recargo'=>'Recargo'] as $c=>$l):?><label class="admin-debt-field"><?=$l?><input class="admin-debt-amount" type="number" name="<?=$c?>" value="<?=htmlspecialchars((string)$adeudo[$c],ENT_QUOTES,'UTF-8')?>" min="0" step="0.01" required></label><?php endforeach;?><label class="admin-debt-field admin-debt-total">Total calculado<input id="admin-debt-total" value="<?=number_format((float)$adeudo['total'],2,'.','')?>" readonly></label><?php if($modo==='editar'):?><p>Estado: <strong>Pendiente</strong></p><?php endif;?><div class="admin-debt-form-actions"><button class="admin-student-submit" type="submit"><?=$modo==='crear'?'Guardar adeudo':'Guardar cambios'?></button><a href="<?=BASE_URL?>/index.php?ruta=admin-adeudos">Cancelar</a></div></form>
